import { Component, Injector, OnDestroy, OnInit } from '@angular/core';
import { Observable } from 'rxjs';
import { takeUntil } from 'rxjs/operators';
import { BaseComponent } from 'src/app/modules/base.component';
import {
  ProjectOfferBlock,
  ProjectOffer,
  ProjectOfferActionStatus,
  ProjectOfferProjectStatus,
  ProjectOffersPaginatedResponse,
  ProjectOffersFilters,
  ProjectOffersService,
  ProjectOfferType,
} from 'src/app/_fake/services/project-offers/project-offers.service';

type ViewMode = 'grid' | 'list';

interface ProjectTypeMeta {
  key: ProjectOfferType;
  labelEn: string;
  labelAr: string;
}

interface StatusFilterOption<T> {
  value: T;
  labelEn: string;
  labelAr: string;
}

@Component({
  selector: 'app-project-offers',
  templateUrl: './project-offers.component.html',
  styleUrl: './project-offers.component.scss'
})
export class ProjectOffersComponent extends BaseComponent implements OnInit, OnDestroy {
  isLoading$: Observable<boolean>;

  offers: ProjectOffer[] = [];
  viewMode: ViewMode = 'grid';
  selectedProjectStatus: ProjectOfferProjectStatus | null = null;
  selectedActionStatus: ProjectOfferActionStatus | null = null;

  currentPage: number = 1;
  rows: number = 10;
  first: number = 0;
  totalRecords: number = 0;

  drawerVisible: boolean = false;
  selectedOffer: ProjectOffer | null = null;

  projectTypeOptions: ProjectTypeMeta[] = [
    { key: 'ad_hoc', labelEn: 'Ad Hoc', labelAr: 'خاص' },
    { key: 'frame_work_agreement', labelEn: 'Framework Agreement', labelAr: 'اتفاقية إطارية' },
    { key: 'urgent_request', labelEn: 'Urgent Request', labelAr: 'طلب عاجل' },
  ];
  projectStatusOptions: StatusFilterOption<ProjectOfferProjectStatus>[] = [
    { value: 'invited', labelEn: 'Invited', labelAr: 'مدعو' },
    { value: 'cancelled', labelEn: 'Cancelled', labelAr: 'ملغي' },
    { value: 'submitted', labelEn: 'Submitted', labelAr: 'مُرسل' },
    { value: 'closed', labelEn: 'Closed', labelAr: 'مغلق' },
  ];
  actionStatusOptions: StatusFilterOption<ProjectOfferActionStatus>[] = [
    { value: 'pending', labelEn: 'Pending', labelAr: 'قيد الانتظار' },
    { value: 'viewed', labelEn: 'Viewed', labelAr: 'تمت المشاهدة' },
    { value: 'offered', labelEn: 'Offered', labelAr: 'تم تقديم العرض' },
    { value: 'declined', labelEn: 'Declined', labelAr: 'مرفوض' },
    { value: 'expired', labelEn: 'Expired', labelAr: 'منتهي' },
  ];

  constructor(injector: Injector, private projectOffersService: ProjectOffersService) {
    super(injector);
    this.isLoading$ = this.projectOffersService.isLoading$;
  }

  ngOnInit(): void {
    this.loadOffers(1);
  }

  loadOffers(page: number): void {
    this.projectOffersService.getProjectOffers(page, this.getActiveFilters())
      .pipe(takeUntil(this.unsubscribe$))
      .subscribe({
        next: (res: ProjectOffersPaginatedResponse) => {
          this.offers = res.data || [];
          this.totalRecords = res.meta?.total ?? 0;
          this.rows = res.meta?.per_page ?? 10;
          this.currentPage = res.meta?.current_page ?? page;
          this.first = (this.currentPage - 1) * this.rows;
        },
        error: (err) => this.handleServerErrors(err),
      });
  }

  onPageChange(event: any): void {
    const page = Math.floor(event.first / event.rows) + 1;
    this.first = event.first;
    this.rows = event.rows;
    this.loadOffers(page);
  }

  onProjectStatusChange(projectStatus: ProjectOfferProjectStatus | null): void {
    this.selectedProjectStatus = projectStatus;
    this.resetPaginationAndReload();
  }

  onActionStatusChange(actionStatus: ProjectOfferActionStatus | null): void {
    this.selectedActionStatus = actionStatus;
    this.resetPaginationAndReload();
  }

  setViewMode(mode: ViewMode): void {
    this.viewMode = mode;
  }

  openDrawer(offer: ProjectOffer): void {
    this.selectedOffer = offer;
    this.drawerVisible = true;
  }

  closeDrawer(): void {
    this.drawerVisible = false;
    this.selectedOffer = null;
  }

  getTypeMeta(key: ProjectOfferType): ProjectTypeMeta | undefined {
    return this.projectTypeOptions.find(o => o.key === key);
  }

  getStatusBadgeClass(offer: ProjectOffer): string {
    const status = (offer.action_status || offer.status || '').toLowerCase();
    switch (status) {
      case 'pending':
      case 'invited':
      case 'viewed':
        return 'badge-light-warning';
      case 'accepted':
      case 'approved':
      case 'offered':
        return 'badge-light-success';
      case 'rejected':
      case 'declined':
      case 'cancelled':
      case 'expired':
        return 'badge-light-danger';
      case 'submitted':
      case 'closed':
        return 'badge-light-primary';
      default:
        return 'badge-light-info';
    }
  }

  getStatusLabel(offer: ProjectOffer): string {
    const status = (offer.action_status || offer.status || '').toLowerCase();
    const labels: { [k: string]: { en: string; ar: string } } = {
      pending: { en: 'Pending', ar: 'قيد الانتظار' },
      invited: { en: 'Invited', ar: 'مدعو' },
      viewed: { en: 'Viewed', ar: 'تمت المشاهدة' },
      offered: { en: 'Offered', ar: 'تم تقديم العرض' },
      accepted: { en: 'Accepted', ar: 'مقبول' },
      approved: { en: 'Approved', ar: 'موافق' },
      rejected: { en: 'Rejected', ar: 'مرفوض' },
      declined: { en: 'Declined', ar: 'مرفوض' },
      cancelled: { en: 'Cancelled', ar: 'ملغي' },
      submitted: { en: 'Submitted', ar: 'مُرسل' },
      closed: { en: 'Closed', ar: 'مغلق' },
      expired: { en: 'Expired', ar: 'منتهي' },
    };
    const match = labels[status];
    if (!match) return status || '-';
    return this.lang === 'ar' ? match.ar : match.en;
  }

  getTypeLabel(type: ProjectOfferType | null | undefined): string {
    if (!type) {
      return '-';
    }

    const meta = this.getTypeMeta(type);
    if (!meta) {
      return this.humanizeValue(type);
    }

    return this.lang === 'ar' ? meta.labelAr : meta.labelEn;
  }

  formatDate(value: string | null | undefined): string {
    if (!value) return '-';
    try {
      const d = new Date(value);
      return d.toLocaleDateString(this.lang === 'ar' ? 'ar-EG' : 'en-US', {
        year: 'numeric', month: 'short', day: 'numeric'
      });
    } catch {
      return value;
    }
  }

  getSummary(offer: ProjectOffer): string {
    return offer.project.service_prompt || offer.project.description || '-';
  }

  getDeadlineLabel(offer: ProjectOffer): string {
    const date = offer.project.deadline_offer || offer.project.deadline;
    return this.formatDate(date);
  }

  getDrawerBackIcon(): string {
    return this.lang === 'ar' ? 'ki-arrow-right' : 'ki-arrow-left';
  }

  getLanguageLabel(value: string | null | undefined): string {
    if (!value) {
      return '-';
    }

    const normalized = value.toLowerCase();
    const labels: Record<string, { en: string; ar: string }> = {
      arabic: { en: 'Arabic', ar: 'العربية' },
      english: { en: 'English', ar: 'الإنجليزية' },
    };

    const match = labels[normalized];
    if (match) {
      return this.lang === 'ar' ? match.ar : match.en;
    }

    return this.humanizeValue(value);
  }

  getPhaseLabel(value: string | null | undefined): string {
    return this.getMappedLabel(value, {
      idea_stage: { en: 'Idea Stage', ar: 'مرحلة الفكرة' },
      validation_stage: { en: 'Validation Stage', ar: 'مرحلة التحقق' },
      growth_stage: { en: 'Growth Stage', ar: 'مرحلة النمو' },
      operating_stage: { en: 'Operating Stage', ar: 'مرحلة التشغيل' },
    });
  }

  getBusinessTypeLabel(value: string | null | undefined): string {
    return this.getMappedLabel(value, {
      entrepreneur: { en: 'Entrepreneur', ar: 'رائد أعمال' },
      startup: { en: 'Startup', ar: 'شركة ناشئة' },
      sme: { en: 'SME', ar: 'منشأة صغيرة أو متوسطة' },
      enterprise: { en: 'Enterprise', ar: 'شركة كبيرة' },
    });
  }

  getDataSourceLabel(value: string | null | undefined): string {
    return this.getMappedLabel(value, {
      primary_data: { en: 'Primary Data', ar: 'بيانات أولية' },
      secondary_data: { en: 'Secondary Data', ar: 'بيانات ثانوية' },
      mixed_data: { en: 'Mixed Data', ar: 'بيانات مختلطة' },
    });
  }

  getWayLabel(value: string | null | undefined): string {
    return this.getMappedLabel(value, {
      physical_workshop: { en: 'Physical Workshop', ar: 'ورشة حضورية' },
      on_platform: { en: 'On Platform', ar: 'على المنصة' },
      online_meeting: { en: 'Online Meeting', ar: 'اجتماع عبر الإنترنت' },
      hybrid: { en: 'Hybrid', ar: 'هجينة' },
    });
  }

  getFormattedValue(value: any): string {
    if (value === null || value === undefined || value === '') {
      return '-';
    }

    if (Array.isArray(value)) {
      return value
        .map(item => this.getFormattedValue(item))
        .filter(item => item !== '-')
        .join(', ') || '-';
    }

    if (typeof value === 'string') {
      return this.humanizeValue(value);
    }

    if (typeof value === 'number' || typeof value === 'boolean') {
      return `${value}`;
    }

    return '-';
  }

  getFilterLabel<T>(option: StatusFilterOption<T> | null | undefined): string {
    if (!option) {
      return '-';
    }

    return this.lang === 'ar' ? option.labelAr : option.labelEn;
  }

  getBlockEntries(block: ProjectOfferBlock | null | undefined): Array<{ key: string; value: any }> {
    if (!block || typeof block !== 'object') {
      return [];
    }

    return Object.entries(block)
      .filter(([_, value]) => value !== null && value !== undefined && value !== '')
      .map(([key, value]) => ({ key, value }));
  }

  getDisplayEntries(block: ProjectOfferBlock | null | undefined): Array<{ label: string; value: string }> {
    return this.getBlockEntries(block)
      .map(({ key, value }) => ({
        label: this.humanizeValue(key),
        value: this.getFormattedValue(value),
      }))
      .filter(entry => entry.value !== '-');
  }

  getDisplayList(values: any[] | null | undefined): string[] {
    if (!Array.isArray(values)) {
      return [];
    }

    return values
      .map(value => this.getFormattedValue(value))
      .filter(value => value !== '-');
  }

  onSendProposal(): void {
    if (!this.selectedOffer) return;
    this.showInfo(
      this.lang === 'ar' ? 'إرسال عرض' : 'Send Proposal',
      this.lang === 'ar' ? 'سيتم توجيهك لإرسال عرضك قريباً.' : 'Proposal flow will open shortly.'
    );
  }

  onAskClient(): void {
    if (!this.selectedOffer) return;
    this.showInfo(
      this.lang === 'ar' ? 'سؤال العميل' : 'Ask Client',
      this.lang === 'ar' ? 'سيتم فتح نافذة المحادثة.' : 'Conversation will open shortly.'
    );
  }

  // Helpers to extract nested component/addon blocks by key
  getComponent(offer: ProjectOffer | null, key: string): any | null {
    if (!offer) return null;
    const list = offer.project?.components || [];
    for (const item of list) {
      if (item && Object.prototype.hasOwnProperty.call(item, key)) {
        return item[key];
      }
    }
    return null;
  }

  getAddon(offer: ProjectOffer | null, key: string): any | null {
    if (!offer) return null;
    const list = offer.project?.addons || [];
    for (const item of list) {
      if (item && Object.prototype.hasOwnProperty.call(item, key)) {
        return item[key];
      }
    }
    return null;
  }

  hasComponents(offer: ProjectOffer | null): boolean {
    return !!(offer && offer.project?.components?.length);
  }

  hasAddons(offer: ProjectOffer | null): boolean {
    return !!(offer && offer.project?.addons?.length);
  }

  trackByOffer(_: number, offer: ProjectOffer): string {
    return offer.uuid;
  }

  trackByValue(_: number, value: string): string {
    return value;
  }

  trackByIndex(index: number): number {
    return index;
  }

  trackByFilterValue<T extends string>(_: number, option: StatusFilterOption<T>): T {
    return option.value;
  }

  trackByEntry(_: number, entry: { key?: string; label?: string; value: any }): string {
    return `${entry.key || entry.label}-${JSON.stringify(entry.value)}`;
  }

  private handleServerErrors(error: any): void {
    if (error?.error?.errors) {
      const serverErrors = error.error.errors;
      for (const key in serverErrors) {
        if (Object.prototype.hasOwnProperty.call(serverErrors, key)) {
          const messages = serverErrors[key];
          this.showError(
            this.lang === 'ar' ? 'حدث خطأ' : 'An error occurred',
            messages.join(', ')
          );
        }
      }
    } else {
      this.showError(
        this.lang === 'ar' ? 'حدث خطأ' : 'An error occurred',
        this.lang === 'ar' ? 'حدث خطأ غير متوقع' : 'An unexpected error occurred.'
      );
    }
  }

  private getMappedLabel(
    value: string | null | undefined,
    labels: Record<string, { en: string; ar: string }>
  ): string {
    if (!value) {
      return '-';
    }

    const normalized = value.toLowerCase();
    const match = labels[normalized];

    if (!match) {
      return this.humanizeValue(value);
    }

    return this.lang === 'ar' ? match.ar : match.en;
  }

  private getActiveFilters(): ProjectOffersFilters {
    return {
      project_status: this.selectedProjectStatus,
      action_status: this.selectedActionStatus,
    };
  }

  private resetPaginationAndReload(): void {
    this.currentPage = 1;
    this.first = 0;
    this.loadOffers(1);
  }

  private humanizeValue(value: string): string {
    return value
      .replace(/[_-]+/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()
      .replace(/\b\w/g, letter => letter.toUpperCase());
  }

  override ngOnDestroy(): void {
    super.ngOnDestroy();
  }
}
<div class="d-flex flex-column gap-5">
  <app-page-header
    [titleEn]="'Project Offers'"
    [titleAr]="'عروض المشاريع'"
    [subtitle]="lang === 'ar' ? 'تصفح وإدارة عروض المشاريع الخاصة بك.' : 'Browse and manage your project offers.'"
    [lang]="lang">
    <i class="ki-outline ki-abstract-26 fs-1 text-info"></i>
  </app-page-header>

  <p-progressBar
    *ngIf="isLoading$ | async"
    mode="indeterminate"
    [style]="{ height: '3px' }">
  </p-progressBar>

  <div class="d-flex align-items-center justify-content-between flex-wrap gap-3">
    <div class="text-gray-600 fs-7">
      <ng-container *ngIf="totalRecords > 0; else emptyCount">
        {{ lang === 'ar' ? 'إجمالي' : 'Total' }}
        <span class="fw-semibold text-gray-900">{{ totalRecords }}</span>
        {{ lang === 'ar' ? 'عرضاً' : 'offers' }}
      </ng-container>
      <ng-template #emptyCount>
        <span class="text-gray-500">{{ lang === 'ar' ? '0 عروض' : '0 offers' }}</span>
      </ng-template>
    </div>

    <div class="d-flex align-items-center flex-wrap gap-3">
      <div class="po-filter">
        <label class="po-filter__label">{{ lang === 'ar' ? 'حالة المشروع' : 'Project Status' }}</label>
        <p-dropdown
          [options]="projectStatusOptions"
          [(ngModel)]="selectedProjectStatus"
          optionValue="value"
          [showClear]="true"
          [placeholder]="lang === 'ar' ? 'كل الحالات' : 'All statuses'"
          styleClass="po-filter__dropdown"
          panelStyleClass="po-filter__panel"
          (onChange)="onProjectStatusChange($event.value)">
          <ng-template pTemplate="selectedItem" let-selectedOption>
            <span *ngIf="selectedOption; else projectStatusPlaceholder">
              {{ getFilterLabel(selectedOption) }}
            </span>
          </ng-template>
          <ng-template pTemplate="item" let-option>
            <span>{{ getFilterLabel(option) }}</span>
          </ng-template>
        </p-dropdown>
        <ng-template #projectStatusPlaceholder>
          <span>{{ lang === 'ar' ? 'كل الحالات' : 'All statuses' }}</span>
        </ng-template>
      </div>

      <div class="po-filter">
        <label class="po-filter__label">{{ lang === 'ar' ? 'حالة الإجراء' : 'Action Status' }}</label>
        <p-dropdown
          [options]="actionStatusOptions"
          [(ngModel)]="selectedActionStatus"
          optionValue="value"
          [showClear]="true"
          [placeholder]="lang === 'ar' ? 'كل الحالات' : 'All statuses'"
          styleClass="po-filter__dropdown"
          panelStyleClass="po-filter__panel"
          (onChange)="onActionStatusChange($event.value)">
          <ng-template pTemplate="selectedItem" let-selectedOption>
            <span *ngIf="selectedOption; else actionStatusPlaceholder">
              {{ getFilterLabel(selectedOption) }}
            </span>
          </ng-template>
          <ng-template pTemplate="item" let-option>
            <span>{{ getFilterLabel(option) }}</span>
          </ng-template>
        </p-dropdown>
        <ng-template #actionStatusPlaceholder>
          <span>{{ lang === 'ar' ? 'كل الحالات' : 'All statuses' }}</span>
        </ng-template>
      </div>

      <div class="po-view-toggle" role="group">
        <button type="button"
                class="po-view-toggle__btn"
                [class.active]="viewMode === 'grid'"
                (click)="setViewMode('grid')"
                [attr.aria-label]="lang === 'ar' ? 'عرض شبكي' : 'Grid view'">
          <i class="ki-outline ki-element-11 fs-5"></i>
        </button>
        <button type="button"
                class="po-view-toggle__btn"
                [class.active]="viewMode === 'list'"
                (click)="setViewMode('list')"
                [attr.aria-label]="lang === 'ar' ? 'عرض قائمـة' : 'List view'">
          <i class="ki-outline ki-row-horizontal fs-5"></i>
        </button>
      </div>
    </div>
  </div>

  <div *ngIf="!(isLoading$ | async) && offers.length === 0" class="po-empty">
    <i class="ki-outline ki-abstract-26 fs-3x text-info mb-4"></i>
    <h6 class="fw-semibold text-gray-800 mb-2">
      {{ lang === 'ar' ? 'لا توجد عروض حتى الآن' : 'No offers yet' }}
    </h6>
    <p class="text-gray-500 fs-7 mb-0">
      {{ lang === 'ar' ? 'ستظهر عروض المشاريع هنا عند توفرها.' : 'Project offers will appear here when available.' }}
    </p>
  </div>

  <div *ngIf="offers.length > 0 && viewMode === 'grid'" class="row g-3">
    <div class="col-12 col-md-6 col-xl-4" *ngFor="let offer of offers; trackBy: trackByOffer">
      <ng-container *ngTemplateOutlet="offerCard; context:{ $implicit: offer, layout: 'grid' }"></ng-container>
    </div>
  </div>

  <div *ngIf="offers.length > 0 && viewMode === 'list'" class="table-responsive po-table-shell">
    <table class="table align-middle fs-6 po-table">
      <thead>
        <tr class="text-inline-start text-gray-500 fw-semibold fs-8 text-uppercase gs-0">
          <th class="min-w-300px">{{ lang === 'ar' ? 'المشروع' : 'Project' }}</th>
          <th class="min-w-170px">{{ lang === 'ar' ? 'النوع' : 'Type' }}</th>
          <th class="min-w-180px">{{ lang === 'ar' ? 'الخدمة' : 'Service' }}</th>
          <th class="min-w-150px">{{ lang === 'ar' ? 'الموعد النهائي' : 'Deadline' }}</th>
          <th class="min-w-130px">{{ lang === 'ar' ? 'الحالة' : 'Status' }}</th>
          <th class="w-100px"></th>
        </tr>
      </thead>

      <tbody class="fw-semibold text-gray-600">
        <tr *ngFor="let offer of offers; trackBy: trackByOffer" class="po-table__row">
          <td>
            <button type="button"
                    class="po-table__project"
                    (click)="openDrawer(offer)">
              <span class="po-table__project-title">{{ offer.project.title }}</span>
              <span class="po-table__project-summary">{{ getSummary(offer) }}</span>
            </button>
          </td>

          <td>
            <div class="po-table__type">
              <ng-container *ngTemplateOutlet="typeIcon; context:{ $implicit: offer.project.type }"></ng-container>
              <span>{{ getTypeLabel(offer.project.type) }}</span>
            </div>
          </td>

          <td>
            <div class="po-table__service-cell" *ngIf="offer.project.service?.name; else emptyService">
              <span class="po-card__service-icon">
                <i class="ki-outline ki-briefcase fs-7"></i>
              </span>
              <span>{{ offer.project.service?.name }}</span>
            </div>
            <ng-template #emptyService>-</ng-template>
          </td>

          <td class="text-gray-800 fw-semibold">{{ getDeadlineLabel(offer) }}</td>

          <td>
            <span class="po-card__status" [ngClass]="getStatusBadgeClass(offer)">
              <span class="po-card__status-dot"></span>
              {{ getStatusLabel(offer) }}
            </span>
          </td>

          <td class="text-end">
            <button type="button"
                    class="po-table__action"
                    (click)="openDrawer(offer)">
              <i class="ki-outline ki-eye fs-5"></i>
            </button>
          </td>
        </tr>
      </tbody>
    </table>
  </div>

  <div *ngIf="totalRecords > rows" class="d-flex justify-content-end">
    <p-paginator
      [rows]="rows"
      [totalRecords]="totalRecords"
      [first]="first"
      (onPageChange)="onPageChange($event)"
      styleClass="p-paginator-sm">
    </p-paginator>
  </div>
</div>

<ng-template #offerCard let-offer let-layout="layout">
  <div class="po-card"
       [class.po-card--list]="layout === 'list'"
       (click)="openDrawer(offer)">
    <div class="po-card__header">
      <span class="po-card-pill po-card-pill--type"
            [class.po-card-pill--adhoc]="offer.project.type === 'ad_hoc'"
            [class.po-card-pill--framework]="offer.project.type === 'frame_work_agreement'"
            [class.po-card-pill--urgent]="offer.project.type === 'urgent_request'">
        <ng-container *ngTemplateOutlet="typeIcon; context:{ $implicit: offer.project.type }"></ng-container>
        <span>{{ getTypeLabel(offer.project.type) }}</span>
      </span>

      <span class="po-card__status" [ngClass]="getStatusBadgeClass(offer)">
        <span class="po-card__status-dot"></span>
        {{ getStatusLabel(offer) }}
      </span>
    </div>

    <div class="po-card__content">
      <h6 class="po-card__title" [title]="offer.project.title">
        {{ offer.project.title }}
      </h6>

      <p class="po-card__summary">
        {{ getSummary(offer) }}
      </p>
    </div>

    <div class="po-card__service" *ngIf="offer.project.service?.name">
      <span class="po-card__service-icon">
        <i class="ki-outline ki-briefcase fs-5"></i>
      </span>
      <span class="po-card__service-text">{{ offer.project.service?.name }}</span>
    </div>

    <div class="po-card__footer">
      <div class="po-card__deadline">
        <span class="po-card__deadline-icon">
          <i class="ki-outline ki-calendar fs-5"></i>
        </span>
        <div class="po-card__deadline-copy">
          <span class="po-card__deadline-label">{{ lang === 'ar' ? 'الموعد النهائي' : 'Deadline' }}</span>
          <span class="po-card__deadline-value">{{ getDeadlineLabel(offer) }}</span>
        </div>
      </div>

      <button type="button"
              class="po-view-button"
              (click)="$event.stopPropagation(); openDrawer(offer)">
        <span>{{ lang === 'ar' ? 'عرض' : 'View' }}</span>
        <i class="ki-outline po-view-button__icon"
           [ngClass]="lang === 'ar' ? 'ki-arrow-left' : 'ki-arrow-right'"></i>
      </button>
    </div>
  </div>
</ng-template>

