<p-sidebar [(visible)]="drawerVisible"
           position="right"
           appendTo="body"
           [modal]="true"
           [dismissible]="true"
           [blockScroll]="false"
           [baseZIndex]="1300"
           [showCloseIcon]="false"
           [style]="{ width: '66vw', maxWidth: '1200px' }"
           styleClass="po-drawer"
           (onHide)="closeDrawer()">
  <ng-container *ngIf="selectedOffer as offer">
    <div class="po-drawer__wrap">
      <div class="po-drawer__main">
        <div class="po-drawer__topbar">
          <button
            type="button"
            class="po-iconbtn"
            (click)="closeDrawer()"
            [attr.aria-label]="lang === 'ar' ? 'رجوع' : 'Back'">
            <i class="ki-outline fs-3" [ngClass]="getDrawerBackIcon()"></i>
          </button>
        </div>

        <div class="po-drawer__body">
          <div class="po-drawer__hero">
            <div class="po-drawer__hero-copy">
              <div class="po-drawer__eyebrow">
                <div class="po-type po-type--hero">
                  <ng-container *ngTemplateOutlet="typeIcon; context:{ $implicit: offer.project.type }"></ng-container>
                  <span class="po-type__label">{{ getTypeLabel(offer.project.type) }}</span>
                </div>
                <span class="badge" [ngClass]="getStatusBadgeClass(offer)">{{ getStatusLabel(offer) }}</span>
              </div>

              <h3 class="po-drawer__title">{{ offer.project.title }}</h3>

              <div class="po-drawer__meta">
                <div class="po-drawer__meta-item">
                  <i class="ki-outline ki-calendar fs-6"></i>
                  <div class="po-meta__text">
                    <span class="po-meta__label">{{ lang === 'ar' ? 'الموعد النهائي' : 'Deadline' }}</span>
                    <span class="po-meta__value">{{ formatDate(offer.project.deadline) }}</span>
                  </div>
                </div>
                <div class="po-drawer__meta-item" *ngIf="offer.project.service?.name">
                  <i class="ki-outline ki-briefcase fs-6"></i>
                  <div class="po-meta__text">
                    <span class="po-meta__label">{{ lang === 'ar' ? 'الخدمة' : 'Service' }}</span>
                    <span class="po-meta__value">{{ offer.project.service?.name }}</span>
                  </div>
                </div>
                <div class="po-drawer__meta-item" *ngIf="offer.project.language">
                  <i class="ki-outline ki-translate fs-6"></i>
                  <div class="po-meta__text">
                    <span class="po-meta__label">{{ lang === 'ar' ? 'اللغة' : 'Language' }}</span>
                    <span class="po-meta__value">{{ getLanguageLabel(offer.project.language) }}</span>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <section class="po-section" *ngIf="offer.project.service_prompt || offer.project.description">
            <h6 class="po-section__title">{{ lang === 'ar' ? 'ملخص المشروع' : 'Project Summary' }}</h6>
            <p class="po-section__text" *ngIf="offer.project.service_prompt">{{ offer.project.service_prompt }}</p>
            <p class="po-section__text" *ngIf="offer.project.description">{{ offer.project.description }}</p>
          </section>

          <section class="po-facts">
            <div class="po-fact po-fact--amber">
              <i class="ki-outline ki-calendar-tick fs-4"></i>
              <div class="po-fact__body">
                <div class="po-fact__label">{{ lang === 'ar' ? 'الموعد النهائي للعرض' : 'Offer Deadline' }}</div>
                <div class="po-fact__value">{{ formatDate(offer.project.deadline_offer) }}</div>
              </div>
            </div>

            <div class="po-fact po-fact--blue">
              <i class="ki-outline ki-element-7 fs-4"></i>
              <div class="po-fact__body">
                <div class="po-fact__label">{{ lang === 'ar' ? 'نوع المشروع' : 'Project Type' }}</div>
                <div class="po-fact__value">{{ getTypeLabel(offer.project.type) }}</div>
              </div>
            </div>

            <div class="po-fact po-fact--green" *ngIf="offer.project.phase">
              <i class="ki-outline ki-chart-pie-simple fs-4"></i>
              <div class="po-fact__body">
                <div class="po-fact__label">{{ lang === 'ar' ? 'المرحلة' : 'Phase' }}</div>
                <div class="po-fact__value">{{ getPhaseLabel(offer.project.phase) }}</div>
              </div>
            </div>

            <div class="po-fact po-fact--slate" *ngIf="offer.project.business_type">
              <i class="ki-outline ki-briefcase fs-4"></i>
              <div class="po-fact__body">
                <div class="po-fact__label">{{ lang === 'ar' ? 'نوع العمل' : 'Business Type' }}</div>
                <div class="po-fact__value">{{ getBusinessTypeLabel(offer.project.business_type) }}</div>
              </div>
            </div>

            <div class="po-fact po-fact--slate" *ngIf="offer.project.industry">
              <i class="ki-outline ki-office-bag fs-4"></i>
              <div class="po-fact__body">
                <div class="po-fact__label">{{ lang === 'ar' ? 'القطاع' : 'Industry' }}</div>
                <div class="po-fact__value">{{ getFormattedValue(offer.project.industry?.name || offer.project.industry) }}</div>
              </div>
            </div>

            <div class="po-fact po-fact--slate" *ngIf="offer.project.language">
              <i class="ki-outline ki-translate fs-4"></i>
              <div class="po-fact__body">
                <div class="po-fact__label">{{ lang === 'ar' ? 'اللغة' : 'Language' }}</div>
                <div class="po-fact__value">{{ getLanguageLabel(offer.project.language) }}</div>
              </div>
            </div>
          </section>

          <section class="po-section" *ngIf="getComponent(offer, 'deliverable-stage') as deliverableStage">
            <h6 class="po-section__title">{{ lang === 'ar' ? 'مراحل التسليم' : 'Deliverable Stages' }}</h6>
            <div class="po-stage-grid">
              <div class="po-stage-card" *ngIf="deliverableStage.first_draft as firstDraft">
                <div class="po-stage-card__head">
                  <span class="po-stage-badge">1</span>
                  <span class="po-stage-card__title">{{ lang === 'ar' ? 'المسودة الأولى' : 'First Draft' }}</span>
                </div>
                <div class="po-kv">
                  <span class="po-kv__key">{{ lang === 'ar' ? 'التاريخ' : 'Date' }}</span>
                  <span class="po-kv__val">{{ formatDate(firstDraft.date) }}</span>
                </div>
                <div class="po-kv" *ngIf="firstDraft.way?.selected">
                  <span class="po-kv__key">{{ lang === 'ar' ? 'طريقة التسليم' : 'Delivery Way' }}</span>
                  <span class="po-kv__val">{{ getWayLabel(firstDraft.way?.selected) }}</span>
                </div>
                <div class="po-kv" *ngIf="firstDraft.way?.address">
                  <span class="po-kv__key">{{ lang === 'ar' ? 'العنوان' : 'Address' }}</span>
                  <span class="po-kv__val">{{ firstDraft.way?.address }}</span>
                </div>
                <div class="po-kv" *ngIf="firstDraft.report_type?.length">
                  <span class="po-kv__key">{{ lang === 'ar' ? 'صيغة التقرير' : 'Report Type' }}</span>
                  <span class="po-kv__val">{{ getFormattedValue(firstDraft.report_type) }}</span>
                </div>
              </div>

              <div class="po-stage-card" *ngIf="deliverableStage.final_version as finalVersion">
                <div class="po-stage-card__head">
                  <span class="po-stage-badge">2</span>
                  <span class="po-stage-card__title">{{ lang === 'ar' ? 'النسخة النهائية' : 'Final Version' }}</span>
                </div>
                <div class="po-kv">
                  <span class="po-kv__key">{{ lang === 'ar' ? 'التاريخ' : 'Date' }}</span>
                  <span class="po-kv__val">{{ formatDate(finalVersion.date) }}</span>
                </div>
                <div class="po-kv" *ngIf="finalVersion.way?.selected">
                  <span class="po-kv__key">{{ lang === 'ar' ? 'طريقة التسليم' : 'Delivery Way' }}</span>
                  <span class="po-kv__val">{{ getWayLabel(finalVersion.way?.selected) }}</span>
                </div>
                <div class="po-kv" *ngIf="finalVersion.way?.address">
                  <span class="po-kv__key">{{ lang === 'ar' ? 'العنوان' : 'Address' }}</span>
                  <span class="po-kv__val">{{ finalVersion.way?.address }}</span>
                </div>
                <div class="po-kv" *ngIf="finalVersion.report_type?.length">
                  <span class="po-kv__key">{{ lang === 'ar' ? 'صيغة التقرير' : 'Report Type' }}</span>
                  <span class="po-kv__val">{{ getFormattedValue(finalVersion.report_type) }}</span>
                </div>
              </div>
            </div>
          </section>

          <section class="po-section" *ngIf="getComponent(offer, 'target-market') as targetMarket">
            <h6 class="po-section__title">{{ lang === 'ar' ? 'السوق المستهدف' : 'Target Market' }}</h6>
            <div class="po-subsection">
              <div class="po-kv" *ngIf="targetMarket.type">
                <span class="po-kv__key">{{ lang === 'ar' ? 'النوع' : 'Type' }}</span>
                <span class="po-kv__val">{{ getFormattedValue(targetMarket.type) }}</span>
              </div>
              <div class="po-chip-group" *ngIf="targetMarket.objects?.length">
                <span class="badge badge-light-info fs-8"
                      *ngFor="let item of targetMarket.objects; trackBy: trackByIndex">
                  {{ item.name }}
                </span>
              </div>
            </div>
          </section>

          <section class="po-section" *ngIf="getComponent(offer, 'data-sources-expected') as dataSources">
            <h6 class="po-section__title">{{ lang === 'ar' ? 'مصادر البيانات' : 'Data Sources' }}</h6>
            <div class="po-subsection">
              <span class="badge badge-light-info fs-8">{{ getDataSourceLabel(dataSources) }}</span>
            </div>
          </section>

          <section class="po-section" *ngIf="hasAddons(offer)">
            <h6 class="po-section__title">{{ lang === 'ar' ? 'الإضافات' : 'Add-ons' }}</h6>
            <div class="po-addon-grid">
              <div class="po-subsection" *ngIf="getAddon(offer, 'kickoff-meeting') as kickoffMeeting">
                <div class="po-subsection__label">{{ lang === 'ar' ? 'اجتماع البدء' : 'Kickoff Meeting' }}</div>
                <div class="po-kv">
                  <span class="po-kv__key">{{ lang === 'ar' ? 'التاريخ' : 'Date' }}</span>
                  <span class="po-kv__val">{{ formatDate(kickoffMeeting.date) }}</span>
                </div>
              </div>

              <div class="po-subsection" *ngIf="getAddon(offer, 'survey-conduct') as surveyConduct">
                <div class="po-subsection__label">{{ lang === 'ar' ? 'إجراء الاستبيان' : 'Survey Conduct' }}</div>
                <div class="po-chip-group" *ngIf="surveyConduct.scopes?.length">
                  <span class="badge badge-light-info fs-8"
                        *ngFor="let scope of surveyConduct.scopes; trackBy: trackByValue">
                    {{ getFormattedValue(scope) }}
                  </span>
                </div>
                <div class="po-kv" *ngIf="surveyConduct.parameters?.size">
                  <span class="po-kv__key">{{ lang === 'ar' ? 'الحجم' : 'Size' }}</span>
                  <span class="po-kv__val">{{ surveyConduct.parameters?.size }}</span>
                </div>
                <div class="po-kv" *ngIf="surveyConduct.parameters?.distribution">
                  <span class="po-kv__key">{{ lang === 'ar' ? 'التوزيع' : 'Distribution' }}</span>
                  <span class="po-kv__val">{{ surveyConduct.parameters?.distribution }}</span>
                </div>
              </div>

              <div class="po-subsection" *ngIf="getAddon(offer, 'consulting-sessions') as consultingSessions">
                <div class="po-subsection__label">{{ lang === 'ar' ? 'جلسات استشارية' : 'Consulting Sessions' }}</div>
                <div class="po-chip-group">
                  <span class="badge badge-light-info fs-8"
                        *ngFor="let item of consultingSessions; trackBy: trackByIndex">
                    {{ formatDate(item.date) }}
                  </span>
                </div>
              </div>

              <div class="po-subsection" *ngIf="getAddon(offer, 'third-party-consultant') as thirdPartyConsultant">
                <div class="po-subsection__label">{{ lang === 'ar' ? 'مستشار خارجي' : 'Third-Party Consultant' }}</div>
                <div class="po-chip-group">
                  <ng-container *ngFor="let item of thirdPartyConsultant; trackBy: trackByIndex">
                    <span class="badge badge-light-info fs-8" *ngIf="item?.date">
                      {{ formatDate(item.date) }}
                    </span>
                  </ng-container>
                </div>
              </div>
            </div>
          </section>
        </div>
      </div>

      <aside class="po-drawer__aside">
        <div class="po-aside-card">
          <div class="po-aside-card__title">
            {{ lang === 'ar' ? 'إجراءات العرض' : 'Offer Actions' }}
          </div>
          <p class="po-aside-card__hint">
            {{ lang === 'ar'
              ? 'راجع التفاصيل ثم أرسل مقترحك أو اطلب توضيحاً من العميل.'
              : 'Review the details, then send your proposal or ask the client for clarification.' }}
          </p>

          <button type="button"
                  class="btn btn-info w-100 mb-2"
                  (click)="onSendProposal()">
            <i class="ki-outline ki-send fs-6 me-1"></i>
            {{ lang === 'ar' ? 'إرسال عرض' : 'Send Proposal' }}
          </button>

          <button type="button"
                  class="btn btn-outline btn-outline-info w-100"
                  (click)="onAskClient()">
            <i class="ki-outline ki-messages fs-6 me-1"></i>
            {{ lang === 'ar' ? 'سؤال العميل' : 'Ask Client' }}
          </button>

          <div class="po-aside-table-wrap">
            <table class="po-aside-table">
              <tbody>
              <tr>
                <th scope="row">{{ lang === 'ar' ? 'الحالة' : 'Status' }}</th>
                <td>
                  <span class="badge" [ngClass]="getStatusBadgeClass(offer)">{{ getStatusLabel(offer) }}</span>
                </td>
              </tr>
              <tr>
                <th scope="row">{{ lang === 'ar' ? 'الخدمة' : 'Service' }}</th>
                <td>{{ offer.project.service?.name || '-' }}</td>
              </tr>
              <tr>
                <th scope="row">{{ lang === 'ar' ? 'نوع المشروع' : 'Project Type' }}</th>
                <td>{{ getTypeLabel(offer.project.type) }}</td>
              </tr>
              <tr>
                <th scope="row">{{ lang === 'ar' ? 'الموعد النهائي' : 'Deadline' }}</th>
                <td>{{ formatDate(offer.project.deadline) }}</td>
              </tr>
              <tr>
                <th scope="row">{{ lang === 'ar' ? 'لغة المشروع' : 'Project Language' }}</th>
                <td>{{ getLanguageLabel(offer.project.language) }}</td>
              </tr>
              </tbody>
            </table>
          </div>
        </div>
      </aside>
    </div>
  </ng-container>
</p-sidebar>
